  const result = useMemo(() => {
    const fat = armyFat(gender, height, neck, waist, hip);
    const max = maxStandard(gender, age);
    return { fat, max, status: fat <= max ? "Meets standard" : "Above standard" };
  }, [age, gender, height, neck, waist, hip]);
  const rows = [["17-20", 20, 30, "Above age/gender max"], ["21-27", 22, 32, "Above age/gender max"], ["28-39", 24, 34, "Above age/gender max"], ["40 and over", 26, 36, "Above age/gender max"]];
